concept_explanation.spring_chaos:
**Chaos Monkey for Spring Boot:**

```java
// pom.xml:
// <dependency> de.codecentric:chaos-monkey-spring-boot:3.1.0 </dependency>

// Enable:
@SpringBootApplication
@EnableChaosMonkey
public class RazorpayApplication { ... }

// application.yml:
chaos:
  monkey:
    enabled: true
    watcher:
      service: true        # @Service methods can be assaulted
      rest-controller: true
      repository: true
    assaults:
      level: 5             # assault 1 in every 5 calls
      latency-active: true
      latency-range-start: 500   # 500ms
      latency-range-end: 2000    # up to 2s
      exceptions-active: false   # keep off by default
      kill-application-active: false
```

```java
// Chaos verification test:
@SpringBootTest(webEnvironment = RANDOM_PORT)
class ChaosVerificationTest {
    @Autowired ChaosMonkeyRequestScope chaosMonkey;
    @Autowired CircuitBreakerRegistry cbRegistry;
    @Autowired HdfcGatewayService svc;

    @Test
    void underLatencyChaos_circuitBreakerOpens() {
        // Enable latency assault:
        chaosMonkey.setLatencyActive(true);
        chaosMonkey.setLatencyRangeStart(3000);
        chaosMonkey.setLatencyRangeEnd(3000); // exactly 3s always

        // Trigger enough calls to open circuit breaker:
        for (int i = 0; i < 20; i++) {
            try { svc.charge("MRC-001", 5000L); } catch (Exception ignored) {}
        }

        // Verify circuit breaker opened:
        CircuitBreaker cb = cbRegistry.circuitBreaker("hdfc-gateway");
        assertNotEquals(CLOSED, cb.getState()); // Should be OPEN or HALF_OPEN
    }
}
```

